codeExamples.code:
// Basic for loop
for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Output: 0 1 2 3 4

// Counting by 3
for (let i = 0; i <= 15; i += 3) {
  console.log(i);
}
// Output: 0 3 6 9 12 15

// Counting backwards
for (let i = 5; i >= 1; i--) {
  console.log(i);
}
// Output: 5 4 3 2 1

// while loop
let a = 1;
while (a <= 3) {
  console.log("while:", a);
  a++;
}

// do...while loop - runs at least once
let b = 10;
do {
  console.log("do-while:", b);
  b++;
} while (b < 5);
// b starts at 10, condition 10 < 5 is false,
// but body still runs once

// for...of with an array
const colors = ["red", "green", "blue"];
for (const color of colors) {
  console.log(color);
}

// for...of with a string
const word = "Hello";
for (const char of word) {
  console.log(char);
}

const student = {
  name: "Kavya",
  age: 16,
  school: "DPS Delhi",
  grade: "11th"
};

for (const key in student) {
  console.log(key + " => " + student[key]);
}

// break: find the first number divisible by 7
for (let i = 1; i <= 100; i++) {
  if (i % 7 === 0) {
    console.log("First multiple of 7:", i);
    break;
  }
}

// continue: print only odd numbers 1-10
for (let i = 1; i <= 10; i++) {
  if (i % 2 === 0) continue;
  console.log(i);
}

// Right triangle pattern
let pattern = "";
for (let i = 1; i <= 5; i++) {
  for (let j = 1; j <= i; j++) {
    pattern += "* ";
  }
  pattern += "\n";
}
console.log(pattern);

// This code runs in a browser with an HTML page
const students = ["Aarav", "Meera", "Rohan", "Diya", "Arjun"];
const ul = document.createElement("ul");

for (const student of students) {
  const li = document.createElement("li");
  li.textContent = student;
  li.style.padding = "8px";
  ul.appendChild(li);
}

document.body.appendChild(ul);
// Creates:
// <ul>
//   <li>Aarav</li>
//   <li>Meera</li>
//   <li>Rohan</li>
//   <li>Diya</li>
//   <li>Arjun</li>
// </ul>

// Creates a 10x10 multiplication table in the browser
const table = document.createElement("table");
table.style.borderCollapse = "collapse";

for (let i = 1; i <= 10; i++) {
  const tr = document.createElement("tr");
  for (let j = 1; j <= 10; j++) {
    const td = document.createElement("td");
    td.textContent = i * j;
    td.style.border = "1px solid #ccc";
    td.style.padding = "8px";
    td.style.textAlign = "center";
    tr.appendChild(td);
  }
  table.appendChild(tr);
}

document.body.appendChild(table);

